1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_DISCOUNT = 15;
3	const BLOCK_SIZE = 3;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_YEARS_THRESHOLD = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	
10	const ITEM_BASE_PRICES: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const MAIN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion"]);
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	type Item = { type: string; enchantment?: number };
23	type Customer = { yearsWithMHPCO?: number };
24	type Scenario = {
25	  customer?: Customer;
26	  steps: { op: string; items: Item[] }[];
27	};
28	
29	function countItemsByType(items: Item[]): Map<string, number> {
30	  const counts = new Map<string, number>();
31	  for (const item of items) {
32	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
33	  }
34	  return counts;
35	}
36	
37	function blockDiscountFor(type: string, count: number): number {
38	  const isComponent = COMPONENT_TYPES.has(type);
39	  const formsBlock = count === BLOCK_SIZE;
40	  return isComponent && formsBlock ? BLOCK_OF_THREE_DISCOUNT : 0;
41	}
42	
43	function basePremiumForGroup(type: string, count: number): number {
44	  return count * ITEM_BASE_PRICES[type] - blockDiscountFor(type, count);
45	}
46	
47	function computePolicyBase(items: Item[]): number {
48	  const itemCountsByType = countItemsByType(items);
49	  let basePremium = 0;
50	  for (const [type, count] of itemCountsByType.entries()) {
51	    basePremium += basePremiumForGroup(type, count);
52	  }
53	  return basePremium;
54	}
55	
56	function computeFirstInsuranceSurcharge(items: Item[]): number {
57	  let surcharge = 0;
58	  for (const item of items) {
59	    if (MAIN_ITEM_TYPES.has(item.type)) {
60	      surcharge += ITEM_BASE_PRICES[item.type] * FIRST_INSURANCE_RATE;
61	    }
62	  }
63	  return surcharge;
64	}
65	
66	function computeHighEnchantmentSurcharge(items: Item[]): number {
67	  let surcharge = 0;
68	  for (const item of items) {
69	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
70	      surcharge += ITEM_BASE_PRICES[item.type] * HIGH_ENCHANTMENT_RATE;
71	    }
72	  }
73	  return surcharge;
74	}
75	
76	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
77	  const years = customer.yearsWithMHPCO ?? 0;
78	  if (years >= LOYALTY_YEARS_THRESHOLD) {
79	    return policyBase * LOYALTY_DISCOUNT_RATE;
80	  }
81	  return 0;
82	}
83	
84	export function runScenario(scenario: unknown): unknown {
85	  const s = scenario as Scenario;
86	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
87	  const items = s.steps[0].items;
88	
89	  const policyBase = computePolicyBase(items);
90	  const highEnchantment = computeHighEnchantmentSurcharge(items);
91	  const firstInsurance = computeFirstInsuranceSurcharge(items);
92	  const loyaltyDiscount = computeLoyaltyDiscount(policyBase, customer);
93	
94	  const premium = policyBase + highEnchantment + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
95	  return { results: [{ premium }] };
96	}
